import 'package:equatable/equatable.dart';

enum PaymentMethod { applePay, googlePay, creditCard, debitCard, stripe, inAppPurchase }

enum PaymentStatus { pending, processing, completed, failed, refunded, cancelled }

enum TransactionType { purchase, subscription, refund, topUp }

