import 'dart:convert';
import 'dart:math';
import 'dart:typed_data';

class PaymentSecurity {
  static final PaymentSecurity _instance = PaymentSecurity._internal();
  factory PaymentSecurity() => _instance;
  PaymentSecurity._internal();

  // PCI DSS Compliance: Never store full card numbers
  // Only store tokenized references

  String tokenizeCard(CardDetails card) {
    // In production, this should call your payment processor's tokenization API
    // Never store raw card data locally
    final random = Random.secure();
    final tokenBytes = List<int>.generate(32, (_) => random.nextInt(256));
    return base64Url.encode(Uint8List.fromList(tokenBytes));
  }

  bool validateCardNumber(String number) {
    // Luhn algorithm
    final digits = number.replaceAll(RegExp(r'\s'), '');
    if (digits.length < 13 || digits.length > 19) return false;
    if (!RegExp(r'^\d+$').hasMatch(digits)) return false;

    int sum = 0;
    bool alternate = false;
    for (int i = digits.length - 1; i >= 0; i--) {
      int n = int.parse(digits[i]);
      if (alternate) {
        n *= 2;
        if (n > 9) n -= 9;
      }
      sum += n;
      alternate = !alternate;
    }
    return sum % 10 == 0;
  }

  bool validateCVC(String cvc) {
    return RegExp(r'^\d{3,4}$').hasMatch(cvc);
  }

  bool validateExpiry(int month, int year) {
    if (month < 1 || month > 12) return false;
    final now = DateTime.now();
    final expiry = DateTime(year, month + 1, 0);
    return expiry.isAfter(now);
  }

  bool validatePaymentRequest(PaymentRequest request) {
    if (request.amount <= 0) return false;
    if (request.amount > 999999.99) return false;

    if (request.cardDetails != null) {
      final card = request.cardDetails!;
      if (!validateCardNumber(card.number)) return false;
      if (!validateCVC(card.cvc)) return false;
      if (!validateExpiry(card.expMonth, card.expYear)) return false;
    }

    return true;
  }

  String sanitizeInput(String input) {
    return input
        .replaceAll(RegExp(r'[<>\"\';&]'), '')
        .trim();
  }

  Map<String, String> generateSecureHeaders(String apiKey) {
    final timestamp = DateTime.now().millisecondsSinceEpoch.toString();
    final nonce = _generateNonce();

    return {
      'Authorization': 'Bearer $apiKey',
      'X-Request-Timestamp': timestamp,
      'X-Request-Nonce': nonce,
      'Content-Type': 'application/json',
      'X-Idempotency-Key': _generateIdempotencyKey(),
    };
  }

  String _generateNonce() {
    final random = Random.secure();
    final bytes = List<int>.generate(16, (_) => random.nextInt(256));
    return base64Url.encode(Uint8List.fromList(bytes));
  }

  String _generateIdempotencyKey() {
    final random = Random.secure();
    final bytes = List<int>.generate(16, (_) => random.nextInt(256));
    return base64Url.encode(Uint8List.fromList(bytes));
  }
}


