import 'dart:convert';

// In production, use flutter_secure_storage package
// This is an abstraction layer

abstract class SecureStorageService {
  Future<void> write(String key, String value);
  Future<String?> read(String key);
  Future<void> delete(String key);
  Future<void> deleteAll();
  Future<bool> containsKey(String key);
}

class SecureStorageServiceImpl implements SecureStorageService {
  // In production: final FlutterSecureStorage _storage = const FlutterSecureStorage();
  final Map<String, String> _mockStorage = {};

  @override
  Future<void> write(String key, String value) async {
    // In production: await _storage.write(key: key, value: value);
    _mockStorage[key] = value;
  }

  @override
  Future<String?> read(String key) async {
    // In production: return await _storage.read(key: key);
    return _mockStorage[key];
  }

  @override
  Future<void> delete(String key) async {
    // In production: await _storage.delete(key: key);
    _mockStorage.remove(key);
  }

  @override
  Future<void> deleteAll() async {
    // In production: await _storage.deleteAll();
    _mockStorage.clear();
  }

  @override
  Future<bool> containsKey(String key) async {
    // In production: return await _storage.containsKey(key: key);
    return _mockStorage.containsKey(key);
  }

  Future<void> storePaymentToken(String customerId, String token) async {
    final key = 'payment_token_$customerId';
    await write(key, token);
  }

  Future<String?> getPaymentToken(String customerId) async {
    final key = 'payment_token_$customerId';
    return await read(key);
  }

  Future<void> storeTransactionHistory(String transactionId, Map<String, dynamic> data) async {
    final key = 'transaction_$transactionId';
    await write(key, jsonEncode(data));
  }

  Future<Map<String, dynamic>?> getTransactionHistory(String transactionId) async {
    final key = 'transaction_$transactionId';
    final data = await read(key);
    if (data != null) {
      return jsonDecode(data) as Map<String, dynamic>;
    }
    return null;
  }
}


